-- 5a. Thêm cột hồ sơ tài xế (nếu chưa có)
alter table users add column if not exists dob text;
alter table users add column if not exists deposit_note text;
alter table users add column if not exists uniform_note text;
alter table users add column if not exists ao_so text;
alter table users add column if not exists ao_size text;
alter table users add column if not exists ao_soluong int;
create table if not exists driver_monthly_stats (
  id text primary key, driver_id text references users(id) on delete cascade,
  month text not null, orders int default 0, income int default 0, rank int, created_at timestamptz default now());

